solution_code:
#include <iostream>

void greet() {
    std::cout << "Welcome to cpproad!" << '\n';
}

int main() {
    greet();

    int id {};
    std::cin >> id;

    std::cout << "User ID: " << id << '\n';

    return 0;
}

